using Microsoft.UI.Xaml;
using Microsoft.UI.Xaml.Media.Imaging;
using Windows.Storage.Streams;

namespace FufuLauncher.Views;

public sealed partial class SponsorWindow : Window
{
    private readonly string base64QrCode = "";

    public SponsorWindow()
    {
        InitializeComponent();
        ExtendsContentIntoTitleBar = true;
    }

    private async void RootGrid_Loaded(object sender, RoutedEventArgs e)
    {
        if (!string.IsNullOrEmpty(base64QrCode))
        {
            await LoadBase64ImageAsync();
        }
    }

    private async Task LoadBase64ImageAsync()
    {
        try
        {
            byte[] imageBytes = Convert.FromBase64String(base64QrCode);
            using var stream = new InMemoryRandomAccessStream();
            using var writer = new DataWriter(stream.GetOutputStreamAt(0));
            writer.WriteBytes(imageBytes);
            await writer.StoreAsync();
            
            var bitmapImage = new BitmapImage();
            await bitmapImage.SetSourceAsync(stream);
            QrCodeImage.Source = bitmapImage;
            
            FadeInStoryboard.Begin();
        }
        catch (Exception)
        {
            ErrorText.Visibility = Visibility.Visible;
        }
    }
}